def load_graph_fixture():
    '''Load a graph from a YAML fixture file.'''
    def _load(fixture_name: str) -> dict:
        fixture_path = Path(__file__).parent / 'fixtures' / f'{fixture_name}.yaml'
        with open(fixture_path) as f:
            return yaml.safe_load(f)
    return _load


@pytest.fixture
def build_graph():
