    def _build(fixture_data: dict) -> tuple[Graph, dict]:
        graph = Graph(directed=True)
        node_map = {}

        for node in fixture_data['nodes']:
            v = graph.insert_vertex(node)
            node_map[node] = v

        for edge_data in fixture_data['edges']:
            src, dst, weight = edge_data
            src_vertex = node_map[src]
            dst_vertex = node_map[dst]
            graph.insert_edge(src_vertex, dst_vertex, weight)

        start_vertex = node_map[fixture_data['start']]
        goal_vertex = node_map[fixture_data['goal']]

        return graph, {
            'start': start_vertex,
            'goal': goal_vertex,
            'expected_length': fixture_data.get('expected_path_length')
        }
    return _build


