def manhattan_heuristic():
    '''Manhattan distance heuristic for grid-based graphs.'''
    def heuristic(node, goal):
        try:
            node_coords = tuple(map(int, node.element().split(',')))
            goal_coords = tuple(map(int, goal.element().split(',')))
            return abs(node_coords[0] - goal_coords[0]) + abs(node_coords[1] - goal_coords[1])
        except (ValueError, AttributeError):
            return 0
    return heuristic


